#[tokio::test]
async fn test_download_basic_pdf() {
    // Download a basic PDF document with download_documents enabled
    let engine_config: CrawlConfig = serde_json::from_str("{\"download_documents\":true,\"respect_robots_txt\":false}")
        .expect("config should parse");
    let engine = create_engine(Some(engine_config)).expect("handle creation should succeed");
    let url = std::env::var("MOCK_SERVER_DOWNLOAD_BASIC_PDF").unwrap_or_else(|_| {
        let _ = common::mock_server_url();
        std::env::var("MOCK_SERVER_DOWNLOAD_BASIC_PDF")
            .unwrap_or_else(|_| format!("{}/fixtures/{}", common::mock_server_url(), "download_basic_pdf"))
    });
    let result = scrape(&engine, &url).await.expect("should succeed");
    assert_eq!(
        result
            .downloaded_document
            .as_ref()
            .unwrap()
            .mime_type
            .to_string()
            .as_str()
            .trim(),
        r#"application/pdf"#,
        "equals assertion failed"
    );
}

